import React, { useState, useEffect, useRef } from "react";
import { NavLink } from "react-router-dom";
import "./Header.css";

export default function Header() {
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [menuOpen, setMenuOpen] = useState(false);

  const searchRef = useRef(null);
  const navRef = useRef(null);
  const menuButtonRef = useRef(null);

  // 🔹 Search close outside
  useEffect(() => {
    const handleClickOutsideSearch = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) {
        setSearchOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutsideSearch);
    return () =>
      document.removeEventListener("mousedown", handleClickOutsideSearch);
  }, []);

  // 🔹 Burger menu close outside
  useEffect(() => {
    const handleClickOutsideMenu = (e) => {
      if (
        menuOpen &&
        navRef.current &&
        !navRef.current.contains(e.target) &&
        menuButtonRef.current &&
        !menuButtonRef.current.contains(e.target)
      ) {
        setMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutsideMenu);
    return () =>
      document.removeEventListener("mousedown", handleClickOutsideMenu);
  }, [menuOpen]);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    alert(`ძებნა: ${searchQuery}`);
    setSearchQuery("");
    setSearchOpen(false);
  };

  return (
    <header className="header">
      {/* Logo */}
      <div className="logo">
        <NavLink to="/">
          <img src="/logo.png" alt="MBTI Logo" />
        </NavLink>
      </div>

      

      {/* Nav */}
      <nav ref={navRef} className={`nav ${menuOpen ? "open" : ""}`}>
        <ul>
          <li><NavLink to="/" end>მთავარი</NavLink></li>
          <li><NavLink to="/mbti-dimensions">MBTI განზომილებები</NavLink></li>
          <li><NavLink to="/articles">სტატიები</NavLink></li>
          <li><NavLink to="/start-test">დაიწყე ტესტი</NavLink></li>
          <li><NavLink to="/register">Sign in</NavLink></li>
        </ul>
      </nav>
      <div className="header-actions" ref={searchRef}>
        <button
          className="search-toggle"
          onClick={() => setSearchOpen((p) => !p)}
          aria-label="ძებნა"
        >
          <img src="/search.png" alt="ძებნა" className="search-icon" />
        </button>

        {searchOpen && (
          <form className="search-form" onSubmit={handleSearchSubmit}>
            <input
              type="text"
              placeholder="ძებნა საიტზე..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              autoFocus
            />
            <button type="submit">ძიება</button>
          </form>
        )}

        {/* Burger */}
        <button
          ref={menuButtonRef}
          className="menu-toggle"
          onClick={() => setMenuOpen((p) => !p)}
          aria-label="მენიუ"
        >
          <img src="/bur.png" alt="მენიუ" className="menu-icon" />
        </button>
      </div>
    </header>
  );
}
